import { ethers } from 'ethers';

// Connect to an Ethereum node (using a public RPC endpoint)
const provider = new ethers.JsonRpcProvider('https://eth-mainnet.g.alchemy.com/v2/YOUR_KEY');

async function exploreEthereum() {
  // Get the latest block number
  const blockNumber = await provider.getBlockNumber();
  console.log('Latest block:', blockNumber);

  // Get a specific block with transactions
  const block = await provider.getBlock(blockNumber);
  console.log('Block hash:', block.hash);
  console.log('Timestamp:', new Date(block.timestamp * 1000).toISOString());
  console.log('Transaction count:', block.transactions.length);
  console.log('Gas used:', block.gasUsed.toString());
  console.log('Gas limit:', block.gasLimit.toString());

  // Check an account balance
  const vitalikAddress = '0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045';
  const balance = await provider.getBalance(vitalikAddress);
  console.log('\nVitalik balance:', ethers.formatEther(balance), 'ETH');

  // Get transaction count (nonce) for an address
  const txCount = await provider.getTransactionCount(vitalikAddress);
  console.log('Transaction count:', txCount);

  // Look at a specific transaction
  if (block.transactions.length > 0) {
    const tx = await provider.getTransaction(block.transactions[0]);
    console.log('\nFirst transaction in block:');
    console.log('From:', tx.from);
    console.log('To:', tx.to);
    console.log('Value:', ethers.formatEther(tx.value), 'ETH');
    console.log('Gas price:', ethers.formatUnits(tx.gasPrice, 'gwei'), 'gwei');
  }
}

exploreEthereum();

import { ethers } from 'ethers';

const provider = new ethers.JsonRpcProvider('https://eth-mainnet.g.alchemy.com/v2/YOUR_KEY');

async function estimateGasCosts() {
  // Get current gas price info (EIP-1559)
  const feeData = await provider.getFeeData();
  console.log('Current Fee Data:');
  console.log('  Gas Price:', ethers.formatUnits(feeData.gasPrice, 'gwei'), 'gwei');
  console.log('  Max Fee Per Gas:', ethers.formatUnits(feeData.maxFeePerGas, 'gwei'), 'gwei');
  console.log('  Max Priority Fee:', ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei'), 'gwei');

  // Estimate gas for a simple ETH transfer
  const transferGas = await provider.estimateGas({
    from: '0x1234567890123456789012345678901234567890',
    to: '0x0987654321098765432109876543210987654321',
    value: ethers.parseEther('1.0'),
  });
  console.log('\nSimple ETH transfer:');
  console.log('  Gas required:', transferGas.toString());
  console.log('  Cost:', ethers.formatEther(transferGas * feeData.gasPrice), 'ETH');

  // Estimate gas for a contract interaction (ERC-20 transfer)
  const erc20Abi = ['function transfer(address to, uint256 amount) returns (bool)'];
  const usdcAddress = '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48';
  const usdcContract = new ethers.Contract(usdcAddress, erc20Abi, provider);

  try {
    const contractGas = await usdcContract.transfer.estimateGas(
      '0x0987654321098765432109876543210987654321',
      1000000 // 1 USDC (6 decimals)
    );
    console.log('\nERC-20 transfer (USDC):');
    console.log('  Gas required:', contractGas.toString());
    console.log('  Cost:', ethers.formatEther(contractGas * feeData.gasPrice), 'ETH');
  } catch (e) {
    console.log('\nERC-20 estimation failed (need valid from address with balance)');
  }

  // Common gas costs for reference
  console.log('\nCommon Gas Costs (reference):');
  console.log('  ETH transfer: 21,000 gas');
  console.log('  ERC-20 transfer: ~46,000-65,000 gas');
  console.log('  ERC-20 approve: ~46,000 gas');
  console.log('  Uniswap swap: ~150,000-300,000 gas');
  console.log('  NFT mint: ~50,000-150,000 gas');
  console.log('  Contract deployment: ~500,000-5,000,000+ gas');
}

estimateGasCosts();

import { ethers } from 'ethers';

// 1. Create a random new wallet
const randomWallet = ethers.Wallet.createRandom();
console.log('=== New Random Wallet ===');
console.log('Address:', randomWallet.address);
console.log('Private Key:', randomWallet.privateKey);
console.log('Mnemonic:', randomWallet.mnemonic.phrase);

// 2. Recover a wallet from a mnemonic phrase
const mnemonic = 'abandon abandon abandon abandon abandon abandon abandon abandon abandon abandon abandon about';
const recoveredWallet = ethers.Wallet.fromPhrase(mnemonic);
console.log('\n=== Recovered from Mnemonic ===');
console.log('Address:', recoveredWallet.address);

// 3. Derive multiple accounts from same mnemonic (HD wallet)
const hdNode = ethers.HDNodeWallet.fromPhrase(mnemonic);
for (let i = 0; i < 3; i++) {
  const child = hdNode.deriveChild(i);
  console.log(`Account ${i}: ${child.address}`);
}

// 4. Create wallet from a private key
const privateKey = '0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80';
const walletFromKey = new ethers.Wallet(privateKey);
console.log('\n=== Wallet from Private Key ===');
console.log('Address:', walletFromKey.address);

// 5. Sign a message
const message = 'Hello, Ethereum!';
const signature = await walletFromKey.signMessage(message);
console.log('\n=== Signed Message ===');
console.log('Message:', message);
console.log('Signature:', signature);

// 6. Verify the signature (recover the signer's address)
const recoveredAddress = ethers.verifyMessage(message, signature);
console.log('Recovered address:', recoveredAddress);
console.log('Matches:', recoveredAddress === walletFromKey.address);

import { ethers } from 'ethers';

// Connect to a test network
const provider = new ethers.JsonRpcProvider('https://eth-sepolia.g.alchemy.com/v2/YOUR_KEY');

// Create wallet from private key (NEVER use real keys in code)
const wallet = new ethers.Wallet('0xYOUR_PRIVATE_KEY', provider);

async function sendTransaction() {
  // 1. Check current balance and nonce
  const balance = await provider.getBalance(wallet.address);
  console.log('Balance:', ethers.formatEther(balance), 'ETH');

  const nonce = await provider.getTransactionCount(wallet.address);
  console.log('Current nonce:', nonce);

  // 2. Get fee data for EIP-1559 transaction
  const feeData = await provider.getFeeData();

  // 3. Build an EIP-1559 transaction
  const tx = {
    type: 2,  // EIP-1559 transaction type
    to: '0xRecipientAddress',
    value: ethers.parseEther('0.01'),  // Send 0.01 ETH
    nonce: nonce,
    gasLimit: 21000n,  // Standard ETH transfer gas
    maxFeePerGas: feeData.maxFeePerGas,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
    chainId: 11155111,  // Sepolia testnet
  };

  console.log('\nTransaction to send:', {
    ...tx,
    value: ethers.formatEther(tx.value) + ' ETH',
    maxFeePerGas: ethers.formatUnits(tx.maxFeePerGas, 'gwei') + ' gwei',
    maxPriorityFeePerGas: ethers.formatUnits(tx.maxPriorityFeePerGas, 'gwei') + ' gwei',
  });

  // 4. Sign and send the transaction
  const signedTx = await wallet.sendTransaction(tx);
  console.log('\nTransaction hash:', signedTx.hash);
  console.log('Waiting for confirmation...');

  // 5. Wait for the transaction to be mined
  const receipt = await signedTx.wait();
  console.log('\nTransaction confirmed!');
  console.log('Block number:', receipt.blockNumber);
  console.log('Gas used:', receipt.gasUsed.toString());
  console.log('Effective gas price:', ethers.formatUnits(receipt.gasPrice, 'gwei'), 'gwei');
  console.log('Total cost:', ethers.formatEther(receipt.gasUsed * receipt.gasPrice), 'ETH');
  console.log('Status:', receipt.status === 1 ? 'Success' : 'Failed');
}

// Example: Calling a smart contract function
async function callContract() {
  const contractAddress = '0xContractAddress';
  const abi = [
    'function transfer(address to, uint256 amount) returns (bool)',
    'function balanceOf(address owner) view returns (uint256)',
  ];

  const contract = new ethers.Contract(contractAddress, abi, wallet);

  // Read-only call (no transaction needed, no gas cost)
  const balance = await contract.balanceOf(wallet.address);
  console.log('Token balance:', balance.toString());

  // State-changing call (sends a transaction, costs gas)
  const tx = await contract.transfer(
    '0xRecipientAddress',
    ethers.parseUnits('100', 18)  // 100 tokens with 18 decimals
  );
  console.log('Transfer tx hash:', tx.hash);

  const receipt = await tx.wait();
  console.log('Transfer confirmed in block:', receipt.blockNumber);
}

sendTransaction();
